Fancybox.bind('[data-fancybox="gallery"]', {});
const getAnimation = (container, path) => {
    return lottie.loadAnimation({
        container: document.querySelector(container),
        renderer: "svg",
        loop: false,
        autoplay: false, // Set autoplay to true
        path: path,
        rendererSettings: {
            progressiveLoad: true, // Boolean, only svg renderer, loads dom elements when needed. Might speed up initialization for large number of elements.
            hideOnTransparent: true, //Boolean, only svg renderer, hides elements when opacity reaches 0 (defaults to true)
            id: 'banner-lottie',
        }
    });
};

const AnimateLottieOnScroll = (obj, scrollTriggerOptions = {}) => {
    const anim = getAnimation(obj.container, obj.path);
    let timeObj = {
        currentFrame: 0
    };
    let endString = 2000;

    ScrollTrigger.create({
        trigger: obj.target,
        scrub: true,
        pin: true,
        // markers: true,
        pinSpacing: true,
        start: "top top",
        onEnter: () => {
            $('header').addClass('fixed')
            gsap.to(['.floatingform-sec', '.callusnow'], {
                autoAlpha: 0
            })
        },
        onLeave: () => {
            gsap.to(['.floatingform-sec', '.callusnow'], {
                autoAlpha: 1
            })
            gsap.to('header', { yPercent: -100 });
        },
        onEnterBack: () => {
            gsap.to('header', { yPercent: 0 })
            gsap.to(['.floatingform-sec', '.callusnow'], {
                autoAlpha: 0
            })
        },
        end: endString,
        ...scrollTriggerOptions,
        onUpdate: (self) => {
            if (scrollTriggerOptions.onUpdate) {
                scrollTriggerOptions.onUpdate(self, anim, timeObj);
            }
        },
    });
};

AnimateLottieOnScroll({
    container: "#myCanvas",
    target: "#hero-animation",
    path: "assets/images/lottie/banner.json",
    duration: 2,
}, {
    onUpdate: (scrollInstance, animationInstance, timeObj) => {
        gsap.to(timeObj, {
            duration: 0.5,
            currentFrame: Math.floor(
                scrollInstance.progress * (animationInstance.totalFrames - 1)
            ),
            onUpdate: () => {
                animationInstance.goToAndStop(timeObj.currentFrame, true);
            },
            ease: "expo",
        });
    },
});

var abtn = $('#add-to-top');

$(window).scroll(function () {
    if ($(window).scrollTop() > 300) {
        abtn.addClass('show');
    } else {
        abtn.removeClass('show');
    }
});

abtn.on('click', function (e) {
    e.preventDefault();
    $('html, body').animate({
        scrollTop: 0
    }, '300');
});


