var screenWidth = window.innerWidth;

function updateCanvasSize() {
    if (screenWidth > 991) {
        largescreen();
    }
}

window.addEventListener('resize', updateCanvasSize);
updateCanvasSize();


function largescreen() {
    let serviceSection = document.querySelector('.serviceSection');
    let cont = document.querySelector('.serviceWrapper');
    // let items = gsap.utils.toArray(".serviceItem");
    let imgBox = gsap.utils.toArray(".imgBox");

    if (serviceSection) {
        let horizontalTl = gsap.timeline({
            scrollTrigger: {
                trigger: serviceSection,
                pin: true,
                scrub: 1,
                //   pinSpacing: true,
                end: () => "+=" + cont.offsetWidth + "px",
            }
        });

        horizontalTl
            .to(cont, {
                xPercent: 0,
                x: () => -70 + "%",
                ease: "none",
                duration: 1
            }, "<")
            .to(imgBox, {
                x: 200 + "%",
                duration: 0.375,
                stagger: {
                    amount: 0.8,
                    ease: "none"
                },
                ease: "none"
            }, "<");
    }
}

let portfolioSection = document.querySelector('.portfolioSection');
let portfoliowrapper = document.querySelector('.portfoliowrapper');
let portfoliowrapper1 = document.querySelector('.portfoliowrapper1');

if (portfolioSection) {
    let horizontalTl = gsap.timeline({
        scrollTrigger: {
            trigger: portfolioSection,
            scrub: 1,
            //   pinSpacing: true,
            end: () => "+=" + portfoliowrapper.offsetWidth + "px",
        }
    });
    if (screenWidth > 991) {
        horizontalTl
            .to(portfoliowrapper, {
                xPercent: 0,
                x: () => -(portfoliowrapper.offsetWidth - document.documentElement.clientWidth) + "px",
                ease: "none",
                duration: 1
            }, "<")
            .to(portfoliowrapper1, {
                xPercent: 0,
                x: () => (portfoliowrapper.offsetWidth - document.documentElement.clientWidth) + "px",
                ease: "none",
                duration: 1
            }, "<")
    } else {
        horizontalTl
            .to(portfoliowrapper, {
                xPercent: 0,
                x: () => -20 + "%",
                ease: "none",
                duration: 1
            }, "<")
            .to(portfoliowrapper1, {
                xPercent: 0,
                x: () => "20%",
                ease: "none",
                duration: 1
            }, "<")
    }
}


