// Lottie Animation
// Wait for the DOM to be fully loaded
document.addEventListener("DOMContentLoaded", function () {
    // Get references to the circles and boxes
    const circles = document.querySelectorAll("circle.cls-3");
    const boxes = document.querySelectorAll(".graphBox");
    const gheadings = document.querySelectorAll(".g-heading");
    const section = document.querySelector('.processSection')
    const sectionHeight = section?.clientHeight


    const parentDiv = document.querySelector('.processSection');
    const parentRect = parentDiv?.getBoundingClientRect(); // Get the parentDiv's dimensions


    circles.forEach((circle, index) => {
        const box = boxes[index];
        const gheading = gheadings[index];
        const circleRect = circle.getBoundingClientRect();

        // Calculate the center of the circle relative to the parentDiv
        const centerX = circleRect.left + circleRect.width / 2 - parentRect.left;
        const centerY = circleRect.top + circleRect.height / 2 - parentRect.top;

        // Calculate the new position for the box
        const boxWidth = box.offsetWidth;
        const boxHeight = box.offsetHeight;


        // Calculate the new position for the box
        const gheadingWidth = gheading.offsetWidth;
        const gheadingHeight = gheading.offsetHeight;

        // Calculate the box's left and top positions
        const newLeft = centerX - boxWidth / 2;
        const newTop = centerY - boxHeight / 2 - parentRect.height * 0.2; // 20% higher on the y-axis

        let customWidth,
            customHeadingWidth;

        // Position the box
        box.style.position = 'absolute';

        if (window.innerWidth <= 1500) {
            customWidth = boxWidth / 1.2;
            customHeadingWidth = boxWidth / 1.55;
        }
        if (window.innerWidth <= 1366) {
            customWidth = boxWidth / 1.2;
            customHeadingWidth = boxWidth / 2.2;
        } else {
            customWidth = boxWidth * 1.2;
            customHeadingWidth = boxWidth * 1.1;
        }


        box.style.left = `${newLeft - customWidth}px`;

        if (index == boxes.length - 1) {
            box.style.top = `${newTop - boxHeight}px`;

        } else {
            box.style.top = `${newTop - (boxHeight * 1.2)}px`;

        }


        // Position the heading
        gheading.style.position = 'absolute';
        gheading.style.left = `${newLeft - customHeadingWidth}px`;
        gheading.style.top = `${newTop - 60}px`;
        // console.log(
        //     'left: ' + gheading.style.left,
        //     'top    : ' + gheading.style.top
        // )
    });


});
$('a[data-toggle="tab"]').on('shown.bs.tab', function (e) {
    var paneTarget = $(e.target).attr('href');
    var $thePane = $('.tab-pane' + paneTarget);
    var paneIndex = $thePane.index();

    // Destroy the existing slider instance if it exists
    if (typeof packageSlider[paneIndex] !== 'undefined') {
        packageSlider[paneIndex].destroy();
    }

    // Reinitialize the slider
    packageSlider[paneIndex] = new Swiper('.tab-pane' + paneTarget + ' .packageSlider', {
        loop: true,
        // autoplay: true,
        slidesPerView: 1,
        spaceBetween: 5,

        observer: true,

        breakpoints: {
            1601: {
                slidesPerView: 4,
                spaceBetween: 20,
            },
            1445: {
                slidesPerView: 3,
                spaceBetween: 40,
            },
            1024: {
                slidesPerView: 3,
                spaceBetween: 35,
            },
            768: {
                slidesPerView: 2,
                spaceBetween: 30,
            },
            640: {
                slidesPerView: 1.5,
                spaceBetween: 25,
            },
            576: {
                slidesPerView: 1.5,
                spaceBetween: 20,
            },
            375: {
                slidesPerView: 1,
                spaceBetween: 10,
            },
        },

        // Navigation arrows
        navigation: {
            nextEl: '.swiper-button-next',
            prevEl: '.swiper-button-prev',
        },
    });
});

